#include<stdio.h>
#include<string.h>
int h[101];
char s[101];
int main()
{
	int n,d,l,is;
	for(int i=0;i<101;i++)
	{
		h[i]=1000;
	}
	scanf("%d%d%s",&n,&d,&s);
	l=strlen(s);
	h[0]=0;
	if(s[0]=='0')
	{
		printf("-1");
		return 0;
	}
	for(int i=1;i<l;i++)
	{
		if(s[i]=='1')
		{
			for(int t=1;t<=d&&i-t>=0;t++)
			{
				if(s[i-t]=='1')
				{
					if(h[i-t]+1<h[i]&&h[i]!=0)
					{
						h[i]=h[i-t]+1;
					}
				}
			}
		}
	}
	if(h[l-1]>999)
	{
		printf("-1");
	}
	else
	{
		printf("%d",h[l-1]);
	}
}

